INSERT INTO `prizes` VALUES (1,2018,'North American / European Championship',9,'Runners and corporate sysops everywhere will soon battle for supremacy at two major upcoming events. The 2018 Android: Netrunner European Championships are coming to the **UK Games Expo** in June, and the 2018 Android: Netrunner North American Championships will follow, taking place at **Gen Con Indy** in August.','https://www.fantasyflightgames.com/en/news/2018/5/7/clones-and-bioroids/',1276,201806,'2018-05-10 18:00:00','2018-05-17 08:54:40',NULL),(2,2018,'Q1 Game Night Kit',1,'','https://www.fantasyflightgames.com/en/news/2018/3/12/corporate-dividends/',1276,201811,'2018-05-13 22:00:00','2018-05-17 08:55:51',NULL),(3,2018,'Store Championship',2,'','https://www.fantasyflightgames.com/en/news/2017/12/4/boost-your-return-on-investment/',1276,201802,NULL,NULL,NULL),(4,2018,'Q2 Game Night Kit',1,'coming soon','https://www.fantasyflightgames.com/en/news/2018/6/1/see-whats-coming/',1276,NULL,'2018-05-17 09:35:46','2018-06-01 14:56:15',NULL),(5,2018,'Regional Championship',3,NULL,'https://www.fantasyflightgames.com/en/news/2018/5/16/get-your-thrills-in-netspace/',1276,NULL,'2018-05-17 09:36:51','2018-05-17 09:36:51',NULL),(6,2017,'Q1 Game Night Kit',1,NULL,'https://www.fantasyflightgames.com/en/news/2016/12/23/all-in-a-days-work/',16051,NULL,'2018-05-17 09:58:29','2018-05-17 09:58:29',NULL),(7,2016,'Summer Game Night Kit',1,NULL,NULL,16051,NULL,'2018-05-17 10:05:47','2018-05-17 10:05:47',NULL),(8,2017,'Q4 Game Night Kit',1,NULL,NULL,16051,NULL,'2018-05-17 10:12:10','2018-05-17 10:12:10',NULL),(9,2017,'Q3 Game Night Kit',1,NULL,NULL,16051,NULL,'2018-05-17 10:14:44','2018-05-17 10:14:44',NULL),(10,2017,'Q2 Game Night Kit',1,NULL,NULL,16051,NULL,'2018-05-17 10:17:08','2018-05-17 10:17:08',NULL),(11,2016,'Spring Game Night Kit',1,NULL,'https://www.fantasyflightgames.com/en/news/2016/2/2/order-spring-2016-tournament-kits-1/',16051,NULL,'2018-05-17 10:20:56','2018-05-17 10:20:56',NULL),(12,2017,'Store Championship',2,NULL,NULL,16051,NULL,'2018-05-17 10:42:04','2018-05-17 10:42:04',NULL),(13,2017,'Regional Championship',3,NULL,NULL,16051,NULL,'2018-05-17 10:54:41','2018-05-17 10:54:41',NULL),(14,2015,'Winter Game Night Kit',1,NULL,NULL,16051,NULL,'2018-05-17 13:17:32','2018-05-17 13:17:32',NULL),(15,2015,'Summer Game Night Kit',1,NULL,NULL,16051,NULL,'2018-05-17 13:19:04','2018-05-17 13:19:04',NULL),(16,2015,'Spring Game Night Kit',1,NULL,NULL,16051,NULL,'2018-05-17 13:20:34','2018-05-17 13:20:34',NULL),(17,2012,'World Championship',5,NULL,'https://www.fantasyflightgames.com/en/news/2012/10/19/rewarding-your-run-on-hq/',1276,NULL,'2018-05-18 04:24:45','2018-05-18 04:24:45',NULL),(18,2012,'Game Night Kit',1,'Also includes Android: Netrunner promotional poster and\ntwo demo posters to identify play areas for new players (one Corp, one Runner).','https://www.fantasyflightgames.com/en/news/2012/10/31/the-rig-makes-the-runner/',1276,0,'2018-05-18 04:36:47','2018-05-18 05:17:28',NULL),(19,2013,'Season 1 Game Night Kit',1,'Also includes 19.5” x 13.5” promotional poster unveiling the latest of Haas-Bioroid’s bioroid research.','https://www.fantasyflightgames.com/en/news/2012/12/17/establish-new-links/',1276,0,'2018-05-18 05:13:16','2018-05-18 05:18:24',NULL),(20,2013,'Season 2 Game Night Kit',1,NULL,NULL,1276,NULL,'2018-05-18 09:29:42','2018-05-18 09:29:42',NULL),(21,2013,'Season 3 Game Night Kit',1,'Also includes promotional poster and pamphlet with information on running your Game Night.','https://www.fantasyflightgames.com/en/news/2013/9/10/retailers-pre-order-your-season-three-game-night-kits-7/',1276,NULL,'2018-05-18 09:30:19','2018-05-18 09:33:59',NULL),(22,2013,'Plugged-In Tour',9,'The Plugged-in Tour is an special tournament tour, and it’s your opportunity to cast a vote for the future of the game. From October 4th to November 3rd, thirty-one Android: Netrunner tournaments will be held at thirty-one different locations throughout the United States and Canada. Tournament attendees will cast their votes for their favorite of two new Runner identities. At the end of the tour, one of these identities will enter the game; the other will be discarded and forever derezzed. Which will it be? You decide.','https://www.fantasyflightgames.com/en/news/2013/8/30/will-you-plug-in/',1276,NULL,'2018-05-18 09:35:40','2018-05-18 11:44:44',NULL),(23,2013,'Regional Championship',3,NULL,NULL,1276,NULL,'2018-05-18 10:19:42','2018-05-18 10:19:42',NULL),(24,2013,'North American Championship',4,'','',1276,NULL,'2018-05-18 10:19:54','2018-05-21 17:02:42',NULL),(25,2013,'World Championship',5,NULL,NULL,1276,NULL,'2018-05-18 10:20:06','2018-05-18 10:20:06',NULL),(26,2014,'Store Championship',2,'Contains Wotan promotional poster.','https://www.fantasyflightgames.com/en/news/2013/11/4/boot-up/',1276,NULL,'2018-05-18 11:36:01','2018-05-18 11:36:37',NULL),(27,2014,'Chronos Protocol Tour',9,'Throughout April 2014, Android: Netrunner players in Europe and other select international regions will gain their opportunity to plug into a special series of events, compete in high-level tournaments, and help shape the future of the game!','https://www.fantasyflightgames.com/en/news/2013/12/19/who-will-control-the-chronos-protocol/',1276,NULL,'2018-05-18 11:46:15','2018-05-28 17:08:49',NULL),(28,2014,'Season 1 Game Night Kit',1,'Contains Planned Assult promotional poster and one informational pamphlet on running a tournament.','https://www.fantasyflightgames.com/en/news/2014/1/2/jack-in-for-a-new-run/',1276,NULL,'2018-05-18 11:48:26','2018-05-18 11:51:51',NULL),(29,2014,'Regional Championship',3,NULL,'https://www.fantasyflightgames.com/en/news/2014/1/15/2014-android-netrunner-regional-championships/',1276,NULL,'2018-05-18 11:52:16','2018-05-18 11:52:16',NULL),(30,2014,'National Championship',4,'','',1276,NULL,'2018-05-18 12:01:50','2018-05-19 05:36:16',NULL),(31,2014,'Summer Game Night Kit',1,'Contains Reina Roja promotional poster.','',1276,NULL,'2018-05-18 12:04