INSERT INTO `tournament_groups` VALUES (1,'Third Hungarian League','We are organising the **Hungarian Netrunner League** for the third year. Each year we have a series tournaments where players gather points in the league.  In the end the four players with the most points battle it out to become league champion.\n\nThe campion and the top 4 players got these fancy badges:\n\n![champion](/img/badges/comm-hun-winner-2017.png) ![top4](/img/badges/comm-hun-2017.png)','Hungary',1276,'2018-04-19 11:40:25','2018-04-19 11:40:25'),(2,'German Nationals 2019','the German Nationals & all connected events','Germany',18163,'2018-04-19 11:50:51','2022-07-05 09:51:07'),(3,'Fourth Hungarian League','**[Current standings](https://docs.google.com/spreadsheets/d/14heNT6Tj7frx9s-PMO8tb-c0i9ELIeLRKqGeScDADO8/edit?usp=sharing)**\n\nWe are organising the **Hungarian Netrunner League** for the fourth year. Each year we have a series tournaments where players gather points in the league. In the end the four players with the most points battle it out to become league champion.','Hungary',1276,'2018-04-20 06:15:28','2018-06-13 09:28:58'),(4,'2018 European Championship','','United Kingdom',1276,'2018-04-20 08:09:34','2018-04-20 08:11:58'),(6,'Penang Netrunner Events','All Penang only events','Malaysia',27062,'2018-04-22 04:26:36','2018-04-22 04:27:06'),(7,'Warsaw Netrunner - Season 13','[Netrunner Warsaw FB Group](https://www.facebook.com/groups/android.netrunner.warszawa/)\n\n[League season FB fb event](https://www.facebook.com/events/536828746679045/)','Poland',1135,'2018-04-23 14:58:19','2018-04-23 15:00:57'),(8,'Bankjob-Series','','Germany',5964,'2018-04-24 14:33:08','2018-04-24 14:33:46'),(9,'Atomic Empire 2018 Regionals','2018 Regional\'s will have a multi-day main event with a side event day 2','United States',16051,'2018-04-26 12:34:37','2018-04-26 12:35:20'),(10,'York Critical Run','York\'s monthly independently ran events.\n\nHanding out NISEI promos, ffg promos, fan made promos and high fives.','United Kingdom',28653,'2018-05-13 17:50:05','2020-01-05 03:26:07'),(11,'ChkDsk York','ChkDsk WAS the name of Travelling Man (TM) York\'s monthy netrunner GNK events.\n\nIt ended. Press F to pay respects','United Kingdom',28653,'2018-05-13 17:50:25','2019-04-20 23:50:50'),(12,'Stimhack Online Cache Refresh',NULL,'online',1276,'2018-06-12 06:48:48','2018-06-12 06:48:48'),(13,'Regional Berlin 2017',NULL,'Germany',18163,'2018-06-18 17:51:30','2018-06-18 17:51:30'),(14,'Hungarian Nationals',NULL,'Hungary',1276,'2018-09-23 12:00:31','2018-09-23 12:00:31'),(15,'Czech Nationals 2o18','\"1st & last\" Czech official National championship weekend!','Czechia',9871,'2018-09-24 07:04:27','2018-09-24 07:12:03'),(16,'Nisei Core Experience Event','','online',1276,'2019-02-05 08:26:06','2019-02-05 08:26:55'),(17,'Berlin League 2019 Q2',NULL,'Germany',18163,'2019-04-05 06:27:50','2019-04-05 06:27:50'),(18,'Fifth Hungarian League (2019-2020)','**[Current standings](https://docs.google.com/spreadsheets/d/1kaLFyhxLiGP-Kvpn0A0JT4ubyEnOTYlSJtGIqzgoqKo/edit?usp=sharing)**\n\nWe are organising the **Hungarian Netrunner League** for the fifth time. Each time we have a series tournaments where players gather points in the league. In the end the four players with the most points battle it out to become league champion.','Hungary',1276,'2019-05-30 07:49:07','2020-02-03 14:21:26'),(19,'German Nats 2019',NULL,'Germany',18163,'2019-09-23 06:29:23','2019-09-23 06:29:23'),(20,'Worlds 2019','[Worlds 2019 Schedule](http://nisei.net/article/Worlds2019Timing)','Netherlands',1276,'2019-10-01 09:51:44','2019-10-01 09:51:44'),(21,'2019 US National Championship',NULL,'United States',27041,'2019-10-09 18:11:01','2019-10-09 18:11:01'),(22,'2019 Bay Area Store Championship Season',NULL,'United States',27041,'2019-10-09 18:12:14','2019-10-09 18:12:14'),(23,'2018 Bay Area Store Championship Season',NULL,'United States',27041,'2019-10-09 18:13:47','2019-10-09 18:13:47'),(24,'SL4V1C N4T10N4L Ch4mp10n5h1p','Slavic National Championship Weekend','Czechia',9871,'2019-11-02 10:28:19','2019-11-02 10:28:19'),(25,'Liverpool Netrunner GNKs','Listings for all Liverpool GNKs!','United Kingdom',25785,'2019-11-14 18:24:09','2019-11-14 18:24:09'),(26,'NISEI',NULL,'online',28653,'2019-12-18 17:59:18','2019-12-18 17:59:18'),(27,'Munich Mining Corp.','','Germany',33786,'2020-01-15 21:27:26','2020-01-15 22:06:38'),(28,'2020 Bay Area Store Championship Season',NULL,'United States',27041,'2020-02-21 20:54:06','2020-02-21 20:54:06'),(29,'B-COM 2020',NULL,'Spain',1276,'2020-03-02 09:18:52','2020-03-02 09:18:52'),(30,'Lockdown Season 1','A series of friendly and casual events online meant to invigorate the meta with custom card bans for each edition and the Diversified Portfolio ID point system.\n\nMore information [here](https://vesper.cyberpunk.me/lockdown)','online',1139,'2020-04-20 12:55:16','2021-10-11 14:28:23'),(31,'RetRunner','Evolving format that started with Original Core, and adds new products each round in chronological order','online',30546,'2020-06-01 12:52:59','2020-06-01 12:52:59'),(32,'GLC Modded','Never-ending Modded league run on GLC Discord server','online',30546,'2020-06-01 12:55:09','2020-06-01 12:55:09'),(33,'Phoenix Meta','Meatspace tournaments hosted in Phoenix','United States',30546,'2020-06-01 13:02:40','2020-06-01 13:02:40'),(34,'2020 NISEI Continental Championships','2020 NISEI Continentals ','online',33530,'2020-07-08 14:31:31','2020-07-08 14:31:31'),(35,'RetRunner',NULL,'online',35874,'2020-08-24 11:18:23','2020-08-24 11:18:23'),(36,'Modded',NULL,'online',35874,'2020-08-24 11:18:43','2020-08-24 11:18:43'),(38,'Net-Giro d\'Italia 2020','Multiple-stage tournament format, which mimics a cycling grand tour, with several general classifications, each with different characteristics.\n\n[Rules](https://alwaysberunning.net/tournaments/2868/net-giro-ditalia-tappa-1stage-1-online)\n\n[General standings](https://docs.google.com/spreadsheets/d/1jqYzoAs7LHV0Ps6FV7GK46qYsrQ_6bgFS30uETTRW00/edit?usp=sharing)\n\n[Final standings](https://alwaysberunning.net/tournaments/2871/net-giro-ditalia-tappa-4stage-4-online)','Italy',31787,'2020-12-23 07:30:47','2021-05-24 19:17:32'),(40,'Brisbane Competitive Reunion Tour','A competitive league for Brisbane, Australia.','Australia',7921,'2021-03-28 23:17:11','2021-03-28 23:22:58'),(41,'2021 NISEI: Continental Championships',NULL,'online',33530,'2021-07-09 14:57:19','2021-07-09 14:57:19'),(42,'Lockdown Season 2','A series of friendly and casual events online meant to invigorate the meta with custom card bans for each edition and the Diversified Portfolio ID point system.\n\nMore information [here](https://vesper.cyberpunk.me/lockdown)','online',1139,'2021-10-11 14:28:31','2021-10-11 14:28:31'),(43,'Net-Giro d\'Italia 2021+1','Multiple-stage tournament format, which mimics a cycling grand tour, with several general classifications, each with different characteristics.\n\n[Rules](https://alwaysberunning.net/tournaments/3152/net-giro-ditalia-tappa-1stage-1-startup)\n\n[General standings](https://docs.google.com/spreadsheets/d/1Tz4uLOIXTmKc7BqcXCqjXjkFmGIN5mA9iGYcTUUB96Q/edit?usp=sharing)\n\n[Final standings](https://alwaysberunning.net/tournaments/3155/net-giro-ditalia-tappa-4stage-4-anrsealed)','Italy',31787,'2022-01-29 11:03:52','2023-06-12 18:53:15'),(44,'Random Access Memories','Random Access Memories is a recurring format with a two week rotation. At the beginning of each two week period, two large releases and 12 data packs will be randomly determined to form the card pool for the tournament and following two weeks.','online',24742,'2022-02-07 12:42:15','2022-02-07 12:43:22'),(45,'Startup Plus League Season 1','Read more about the format here: https://vesper.cyberpunk.me/startup-plus\n\nIn short: Startup plus Standard legal IDs and one playset of a Standard legal card for both Runner and Corp.','online',1139,'2022-02-20 15:20:53','2022-03-22 00:04:44'),(46,'2022 Off The Grid Championship Weekend','2022 Off The Grid Championship Weekend will consist of two tournaments: The 2022 US National Championship and Gods of the Grid!\n\nA $55 one-size-fits-all ticket will allow entry to all events, $30 for National Championship ONLY, or $25 Gods of the Grid ONLY.','United States',8349,'2022-03-21 16:39:31','2022-05-24 18:26:56'),(47,'2022 World Championship Weekend','The 2022 World Championship Weekend is a celebration of all things Netrunner. It will consist of three separate tournaments.\n\nA $75 one-size-fits-all ticket will allow entry to all events, or there are $30 individual event tickets for any of the three events.','Canada',33530,'2022-06-17 16:47:27','2022-06-17 16:54:28'),(48,'Learning To Run – The Paradice Netrunner League – Season 1','Netrunner league and meetup at the [Paradice Board Game Bar](https://www.paradice-board-game-bar.at/) in Vienna, Austria. Takes place every second Tuesday.\n\nOur next date and more information [here](https://bit.ly/3t5vCIV).','Austria',38747,'2022-06-24 04:04:36','2022-09-02 07:37:19'),(49,'2022 NISEI Australian Championships','Compiling all information about the 2022 events.','Australia',6244,'2022-07-04 03:09:41','2022-07-04 03:09:41'),(50,'German Nationals 2022','the German Nationals & all connected events','Germany',18163,'2022-07-05 09:51:23','2022-07-05 09:51:23'),(51,'Melbourne Circuit Opener collection','The 2022 Melbourne/Narrm Circuit Opener will offer 2 tournaments, run simultaneously: Standard and Startup. Play whichever you prefer!','Australia',6244,'2022-07-23 08:18:09','2022-07-23 08:18:09'),(52,'2022 Continental Championships','The 2022 Continental Championship Season begins August 20th. The theme this year: **Champions**. Will you have what it takes to become one?','online',33530,'2022-07-25 00:16:53','2022-07-25 00:16:53'),(53,'Ulm Circuit Openers 2022','','Germany',14354,'2022-08-31 11:53:42','2023-09-04 15:11:31'),(54,'Learning To Run – The Paradice Netrunner League – Season 2','Netrunner league and meetup at the [Paradice Board Game Bar](https://www.paradice-board-game-bar.at/) in Vienna, Austria. Takes place every second Tuesday.\n\nOur next date and more information [here](https://bit.ly/3t5vCIV).','Austria',38747,'2022-09-10 05:44:06','2022-09-10 05:44:06'),(55,'Learning To Run – The Paradice Netrunner Meetup','Netrunner meetup at the [Paradice Board Game Bar](https://www.paradice-board-game-bar.at/) in Vienna, Austria. Takes place every second Tuesday.','Austria',38747,'2023-01-24 10:42:42','2024-03-07 08:39:14'),(56,'Barcelona GNKs','Irregular community meetups to play casually, win some prizes, and promote the game in the city of BCN :)','Spain',1139,'2023-02-20 17:08:43','2023-02-20 17:08:43'),(57,'V-COM','B-COM is **so** last year (and hopefully next year)...\n\nReady to warm up for Worlds 2023 in Barcelona?\n\nTake part in V-COM!','online',1139,'2023-02-20 17:19:07','2023-02-21 15:36:09'),(58,'2023 Off The Grid Championship Weekend','2023 Off The Grid Championship Weekend will consist of two tournaments: The 2023 Midwest Championship and Gods of the Grid!\n\nDue to a gracious sponsor, a $25 one-size-fits-all ticket will allow entry to all events. Thank you so much, mysterious sponsor, you know who you are!','United States',8349,'2023-03-11 17:20:34','2023-03-11 20:58:54'),(59,'Up the Beanstalk','*Up the Beanstalk* is a tournament series in Vienna, Austria jointly organized by the [CARD-Club](http://www.card-club.org/) and [Paradice](https://www.paradice-board-game-bar.at/).\n\nThe series consists of four tournaments themed around the journey from Earth to the Moon along the New Angeles Space Elevator and beyond. Two tournaments each are played in the Startup and Standard format.','Austria',38747,'2023-03-16 06:10:25','2023-03-16 06:10:25'),(60,'Net-Giro d\'Italia 2023','Multiple-stage tournament format, which mimics a cycling grand tour, with several general classifications, each with different characteristics.\n\n[Rules and final standings](https://alwaysberunning.net/tournaments/3697/net-giro-ditalia-2023)\n\n[Standings](https://docs.google.com/spreadsheets/d/1gXWRNDpBf_iK6Ta2RUiLevRjLxrDzFibUocISP-EqeI/edit?usp=sharing)','Italy',31787,'2023-03-29 19:34:42','2023-10-10 06:38:20'),(61,'Aesop\'s Taproom- Milwaukee Biweekly Netrunner','Milwaukee/ SE Wisconsin Netrunner night, every two weeks at Indeed Brewing in Milwaukee, Wisconsin','United States',37345,'2023-05-07 15:16:42','2023-05-07 15:16:42'),(62,'2023 Continental Championships','The 2023 Continental Championship Season begins August 5th. Do you have what it takes to become a champion?','online',33530,'2023-05-26 14:18:54','2023-05-26 14:18:54'),(63,'2023 World Championship Weekend','The 2023 World Championship Weekend is a celebration of all things Netrunner. It will consist of three separate tournaments.\n\nA €75 one-size-fits-all ticket will allow entry to all events. ','Spain',33530,'2023-06-19 13:03:19','2023-06-19 13:03:19'),(65,'Italian National 2023','You can find a full description [here](https://alwaysberunning.net/tournaments/3793/italian-national-2023-overview).','Italy',31787,'2023-10-10 06:37:09','2023-10-10 06:37:09'),(66,'Netrunner Deutschland (Germany)','Hi,\n\ndie dt. Netrunner-Community versammelt sich mittlerweile großteils am Netrunner-Deutschland-Discord-Channel.\n\nKommt gern vorbei!\n\nhttps://discord.gg/UrKxTGZ\n\nAußerdem haben wir derzeit ein zweiwöchentliches online-Meetup dort für die dt. Community - auch hier gilt. einfach vorbei kommen und mitmachen!\nTermine findet ihr immer aktuell im Discord.\n\n-------------------------------\n\nHi,\n\nthe German Netrunner community is now largely gathered on the Netrunner Germany Discord channel.\n\nFeel free to drop by!\n\nhttps://discord.gg/UrKxTGZ\n\nWe also currently have a bi-weekly online meetup there for the German community - just drop by and join in!\nYou can always find the latest dates in the Discord.','Germany',23078,'2024-02-10 07:38:06','2024-02-10 07:59:00'),(67,'Netrunner Frankfurt','Hi,\n\nwir treffen uns in Frankfurt regelmäßig live zum spielen - aktuell meistens alle 2 Wochen, Donnerstagabends im Moxy in der Innenstadt.\n\nFragen und Infos in unserer Netrunner-Frankfurt What\'s App-Gruppe:\n- fragt mich bitte irgendwo direkt für den link - wir haben da n bisschen spam-probleme -\n\noder im Netrunner-Deutschland-Discord-Channel:\nhttps://discord.gg/UrKxTGZ\n\noder per Mail an mich :)\ntradonnetrunner@hotmail.com\n\n-------------------------------\n\nHi,\n\nwe meet regularly in Frankfurt to play live - currently mostly every 2 weeks, Thursday evenings at the Moxy in the city center.\n\nQuestions and info in our Netrunner-Frankfurt What\'s App group:\n- pls ask me directly for a link - we do have some spam-problems - \n\nor in the Netrunner Germany Discord channel:\nhttps://discord.gg/UrKxTGZ\n\nor by e-mail to me :)\ntradonnetrunner@hotmail.com','Germany',23078,'2024-02-10 07:53:15','2024-05-17 05:03:51'),(68,'2024 Off The Grid Championship Weekend',NULL,'United States',8349,'2024-06-07 11:37:07','2024-06-07 11:37:07'),(69,'Ulm Circuit Opener and Startup 2024',NULL,'Germany',14354,'2024-08-11 07:44:25','2024-08-11 07:44:25'),(70,'Netrunner Draft',NULL,'United States',23117,'2025-01-04 01:51:24','2025-01-04 01:51:24'),(71,'Salt City Grid','Organizing a handful of Northern Utah events from Davis to Salt Lake to Utah county and more.','United States',49925,'2025-01-08 17:43:24','2025-03-13 12:36:38'),(72,'Lockdown',NULL,'United States',4990,'2025-01-14 23:53:23','2025-01-14 23:53:23'),(73,'Standard-sanctioned',NULL,'United States',4990,'2025-01-14 23:54:21','2025-01-14 23:54:21'),(74,'Team',NULL,'United States',4990,'2025-01-14 23:56:10','2025-01-14 23:56:10'),(75,'Startup',NULL,'United States',4990,'2025-01-14 23:56:26','2025-01-14 23:56:26'),(76,'*ALL* ONLINE',NULL,'online',4990,'2025-01-14 23:57:12','2025-01-14 23:57:12'),(77,'*ALL* OTHER IN-PERSON',NULL,'United States',4990,'2025-01-15 00:08:33','2025-01-15 00:08:33'),(79,'Netrunner Portugalete','Grupo de juego de Netrunner en Portugalete, Bizkaia\n\n','Spain',14136,'2025-03-26 09:01:17','2025-03-26 09:01:37'),(80,'Online Showdowns','The Online Showdown event group','online',37550,'2025-04-11 23:34:39','2025-04-11 23:34:39'),(81,'Online Chimera Events','The Chimera event group','online',37550,'2025-04-11 23:36:12','2025-04-11 23:36:12'),(82,'EMEA Continentals 2025 @Cologne','','Germany',34833,'2025-04-28 19:39:02','2025-04-28 19:39:02'),(83,'Shipment to Cologne','Fundraising tournaments for EMEA 25','online',34833,'2025-04-28 19:39:42','2025-04-28 19:39:42'),(84,'*Working Title* Underground Crew ','JWW Sports Cards & Gaming Local Crew','United States',49460,'2025-12-25 07:39:33','2025-12-25 07:42:00'),(85,'Mox Boarding House','LCG Night every Wednesday from 6-9 PM.','United States',54640,'2026-01-29 18:00:06','2026-01-29 18:00:32');
